import {
  Masthead,
  MastheadBrand,
  MastheadContent,
  MastheadMain,
  MastheadToggle,
  Page,
  PageSection,
  PageSidebar,
  PageSidebarBody,
  Button,
  Toolbar,
  ToolbarContent,
  ToolbarGroup,
  ToolbarItem,
  Label,
  Title,
} from "@patternfly/react-core";
import { BarsIcon, MinusIcon, PlusIcon, ExpandIcon, SunIcon, MoonIcon } from "@patternfly/react-icons";
import { useState, useMemo, useEffect } from "react";
import { CanvasContainer } from "./components/canvas/CanvasContainer";
import { TaskDetailPanel } from "./components/panels/TaskDetailPanel";
import { FleetSidebarContent } from "./components/sidebar/FleetSidebar";
import { getLODLevel, useViewport } from "./stores/viewport";
import { useScenario, SCENARIO_COLORS } from "./stores/scenario";
import { generateMockTasks, tasksToSoA } from "./utils/mockData";
import { detectConflicts, getConflictingTaskIndices } from "./utils/conflictDetection";
import { MOCK_RESOURCE_PROJECTION } from "./utils/resourceUtils";
import { getUtilizationStatus } from "./types/resource";
import type { UtilizationStatus } from "./types/resource";

type Theme = "light" | "dark";

// Map utilization status to PatternFly label color
function getUtilizationColor(status: UtilizationStatus): "green" | "yellow" | "orange" | "red" {
  switch (status) {
    case "optimal": return "green";
    case "under_utilized": return "yellow";
    case "near_capacity": return "orange";
    case "overloaded": return "red";
  }
}

export function App() {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [theme, setTheme] = useState<Theme>("light"); // Default to light
  const { state: viewportState, actions: viewportActions } = useViewport();
  const { state: scenarioState, actions: scenarioActions } = useScenario();

  // Apply theme to document
  useEffect(() => {
    document.documentElement.setAttribute("data-theme", theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme((prev) => (prev === "light" ? "dark" : "light"));
  };

  const lodLevel = getLODLevel(viewportState.zoom);
  const scenarioColors = SCENARIO_COLORS[scenarioState.mode];

  // Generate mock task data (same as CanvasContainer)
  const tasks = useMemo(() => {
    const rawTasks = generateMockTasks(128, 12, 4); // 128 trains, 12 years, ~4 tasks/year
    return tasksToSoA(rawTasks);
  }, []);

  // Compute conflicts
  const { conflicts, conflictIndices } = useMemo(() => {
    const detected = detectConflicts(tasks);
    const indices = getConflictingTaskIndices(detected);
    return { conflicts: detected, conflictIndices: indices };
  }, [tasks]);

  // Compute utilization from resource projection
  const utilization = useMemo(() => {
    const currentYear = new Date().getFullYear();
    const yearlyData = MOCK_RESOURCE_PROJECTION.yearlySummaries.find(
      (y) => y.year === currentYear
    );

    // Use first year if current year not found, or sensible default
    const avgUtilization = yearlyData?.averageUtilization
      ?? MOCK_RESOURCE_PROJECTION.yearlySummaries[0]?.averageUtilization
      ?? 85;

    return {
      percent: Math.round(avgUtilization),
      status: getUtilizationStatus(avgUtilization),
    };
  }, []);

  const header = (
    <Masthead>
      <MastheadMain>
        <MastheadToggle>
          <Button
            variant="plain"
            onClick={() => setSidebarOpen(!sidebarOpen)}
            aria-label="Toggle sidebar"
          >
            <BarsIcon />
          </Button>
        </MastheadToggle>
        <MastheadBrand>
          <Title headingLevel="h1" size="lg" style={{ color: "white" }}>
            MMS
          </Title>
        </MastheadBrand>
      </MastheadMain>
      <MastheadContent>
        <Toolbar>
          <ToolbarContent>
            {/* Zoom Controls */}
            <ToolbarGroup variant="action-group">
              <ToolbarItem>
                <Button variant="plain" onClick={() => viewportActions.zoomOut()} aria-label="Zoom out">
                  <MinusIcon />
                </Button>
              </ToolbarItem>
              <ToolbarItem>
                <Label isCompact>{(viewportState.zoom * 100).toFixed(0)}%</Label>
              </ToolbarItem>
              <ToolbarItem>
                <Button variant="plain" onClick={() => viewportActions.zoomIn()} aria-label="Zoom in">
                  <PlusIcon />
                </Button>
              </ToolbarItem>
              <ToolbarItem>
                <Button variant="plain" onClick={() => viewportActions.resetView()} aria-label="Fit to view">
                  <ExpandIcon />
                </Button>
              </ToolbarItem>
            </ToolbarGroup>

            {/* LOD Indicator */}
            <ToolbarGroup variant="action-group">
              <ToolbarItem>
                <Label
                  color={lodLevel === "MACRO" ? "orange" : lodLevel === "MESO" ? "blue" : "green"}
                >
                  {lodLevel}
                </Label>
              </ToolbarItem>
            </ToolbarGroup>

            {/* Mode Toggle */}
            <ToolbarGroup variant="action-group">
              <ToolbarItem>
                <Button
                  variant="plain"
                  onClick={() => scenarioActions.toggleMode()}
                  style={{
                    padding: "4px 12px",
                    borderRadius: "16px",
                    backgroundColor: scenarioState.mode === "sandbox" ? "#7c3aed" : "#0066cc",
                    color: "white",
                    fontWeight: 500,
                  }}
                >
                  {scenarioColors.label}
                  {scenarioState.isDirty && " *"}
                </Button>
              </ToolbarItem>
              {scenarioState.mode === "sandbox" && scenarioState.modifications.size > 0 && (
                <ToolbarItem>
                  <Label isCompact color="purple">
                    {scenarioState.modifications.size} changes
                  </Label>
                </ToolbarItem>
              )}
            </ToolbarGroup>

            {/* Theme Toggle */}
            <ToolbarGroup variant="action-group">
              <ToolbarItem>
                <button
                  onClick={toggleTheme}
                  className="theme-toggle-btn"
                  aria-label={`Switch to ${theme === "light" ? "dark" : "light"} theme`}
                  title={`Switch to ${theme === "light" ? "dark" : "light"} theme`}
                >
                  {theme === "light" ? <MoonIcon /> : <SunIcon />}
                  <span style={{ color: "var(--mms-text-primary)" }}>
                    {theme === "light" ? "Dark" : "Light"}
                  </span>
                </button>
              </ToolbarItem>
            </ToolbarGroup>

            {/* KPIs */}
            <ToolbarGroup align={{ default: "alignEnd" }}>
              <ToolbarItem>
                <Label isCompact>Tasks: {tasks.count.toLocaleString()}</Label>
              </ToolbarItem>
              <ToolbarItem>
                <Label isCompact color={conflicts.length > 0 ? "red" : "green"}>
                  Conflicts: {conflicts.length}
                </Label>
              </ToolbarItem>
              <ToolbarItem>
                <Label isCompact color={getUtilizationColor(utilization.status)}>
                  Utilization: {utilization.percent}%
                </Label>
              </ToolbarItem>
            </ToolbarGroup>
          </ToolbarContent>
        </Toolbar>
      </MastheadContent>
    </Masthead>
  );

  const sidebar = (
    <PageSidebar isSidebarOpen={sidebarOpen}>
      <PageSidebarBody style={{ height: "calc(100vh - 73px)" }}>
        <FleetSidebarContent />
      </PageSidebarBody>
    </PageSidebar>
  );

  return (
    <Page masthead={header} sidebar={sidebar} className={theme === "dark" ? "pf-v6-theme-dark" : "pf-v6-theme-light"} style={{ height: "100vh" }}>
      <PageSection
        isFilled
        padding={{ default: "noPadding" }}
        style={{
          backgroundColor: "var(--mms-bg-canvas)",
          position: "relative",
          height: "calc(100vh - 73px)", // Subtract header height
          minHeight: "calc(100vh - 73px)",
        }}
      >
        <TaskDetailPanel tasks={tasks} conflictIndices={conflictIndices}>
          <CanvasContainer tasks={tasks} />
        </TaskDetailPanel>
      </PageSection>
    </Page>
  );
}

