     1→import { useCallback, useEffect, useMemo, useRef } from "react";
     2→import { Canvas, useFrame, useThree } from "@react-three/fiber";
     3→import * as THREE from "three";
     4→import {
     5→  getLODLevel,
     6→  getLODOpacity,
     7→  useViewport,
     8→  viewportStore,
     9→  WORLD_BOUNDS,
    10→} from "../../stores/viewport";
    11→import { useInteraction } from "../../stores/interaction";
    12→import { useScenario, SCENARIO_COLORS } from "../../stores/scenario";
    13→import { MacroHeatmapCells, MacroYearMarkers } from "../../render/MacroLayer";
    14→import { MesoTaskBlocks, MesoGridLines } from "../../render/MesoLayer";
    15→import { MicroTaskCards, MicroTaskLabels, MicroWeeklyGrid, MicroRowBackgrounds } from "../../render/MicroLayer";
    16→import { RenderIndicator } from "./RenderIndicator";
    17→import type { TaskSoA } from "../../utils/mockData";
    18→import { detectConflicts, getConflictingTaskIndices } from "../../utils/conflictDetection";
    19→
    20→interface CanvasContainerProps {
    21→  tasks: TaskSoA;
    22→}
    23→
    24→// Unified camera controller - syncs Three.js camera with viewport state
    25→function UnifiedCameraController() {
    26→  const { state } = useViewport();
    27→  const { camera, size } = useThree();
    28→  const loggedRef = useRef(false);
    29→
    30→  useFrame(() => {
    31→    if (camera instanceof THREE.OrthographicCamera) {
    32→      // Update camera position
    33→      camera.position.set(state.x, state.y, 100);
    34→
    35→      // Update frustum based on viewport size and zoom
    36→      const halfWidth = size.width / 2 / state.zoom;
    37→      const halfHeight = size.height / 2 / state.zoom;
    38→      camera.left = -halfWidth;
    39→      camera.right = halfWidth;
    40→      camera.top = halfHeight;
    41→      camera.bottom = -halfHeight;
    42→      camera.updateProjectionMatrix();
    43→
    44→      // Debug log once
    45→      if (!loggedRef.current) {
    46→        loggedRef.current = true;
    47→        console.log("[UnifiedCanvas Camera]", {
    48→          position: [state.x, state.y, 100],
    49→          frustum: { left: -halfWidth, right: halfWidth, top: halfHeight, bottom: -halfHeight },
    50→          zoom: state.zoom,
    51→        });
    52→      }
    53→    }
    54→  });
    55→
    56→  return null;
    57→}
    58→
    59→// LOD Layer wrapper - controls visibility via Three.js group
    60→interface LODLayerProps {
    61→  visible: boolean;
    62→  opacity: number;
    63→  children: React.ReactNode;
    64→}
    65→
    66→function LODLayer({ visible, opacity, children }: LODLayerProps) {
    67→  const groupRef = useRef<THREE.Group>(null);
    68→
    69→  useFrame(() => {
    70→    if (groupRef.current) {
    71→      groupRef.current.visible = visible && opacity > 0.01;
    72→    }
    73→  });
    74→
    75→  if (!visible && opacity < 0.01) return null;
    76→
    77→  return <group ref={groupRef}>{children}</group>;
    78→}
    79→
    80→// Props for unified scene
    81→interface UnifiedSceneProps {
    82→  tasks: TaskSoA;
    83→  conflictIndices: Set<number>;
    84→  onTaskClick: (index: number) => void;
    85→}
    86→
    87→// Unified scene containing all LOD layers
    88→function UnifiedScene({ tasks, conflictIndices, onTaskClick }: UnifiedSceneProps) {
    89→  const { state } = useViewport();
    90→  const lodLevel = getLODLevel(state.zoom);
    91→  const lodOpacity = getLODOpacity(state.zoom);
    92→
    93→  return (
    94→    <>
    95→      <UnifiedCameraController />
    96→
    97→      {/* MACRO Layer - Heatmap (visible when zoomed out) */}
    98→      <LODLayer visible={lodLevel === "MACRO" || lodOpacity.macro > 0.01} opacity={lodOpacity.macro}>
    99→        <MacroHeatmapCells tasks={tasks} />
   100→        <MacroYearMarkers />
   101→      </LODLayer>
   102→
   103→      {/* MESO Layer - Task Blocks (default working view) */}
   104→      <LODLayer visible={lodLevel === "MESO" || lodOpacity.meso > 0.01} opacity={lodOpacity.meso}>
   105→        <MesoTaskBlocks tasks={tasks} conflictIndices={conflictIndices} onTaskClick={onTaskClick} />
   106→        <MesoGridLines />
   107→      </LODLayer>
   108→
   109→      {/* MICRO Layer - Task Cards with labels (visible when zoomed in) */}
   110→      <LODLayer visible={lodLevel === "MICRO" || lodOpacity.micro > 0.01} opacity={lodOpacity.micro}>
   111→        <MicroRowBackgrounds />
   112→        <MicroWeeklyGrid />
   113→        <MicroTaskCards tasks={tasks} />
   114→        <MicroTaskLabels tasks={tasks} />
   115→      </LODLayer>
   116→    </>
   117→  );
   118→}
   119→
   120→export function CanvasContainer({ tasks }: CanvasContainerProps) {
   121→  const { state, actions } = useViewport();
   122→  const { state: interactionState, actions: interactionActions } = useInteraction();
   123→  const { state: scenarioState } = useScenario();
   124→  const containerRef = useRef<HTMLDivElement>(null);
   125→  const dragStartRef = useRef<{ x: number; y: number; time: number } | null>(null);
   126→  const lastPosRef = useRef<{ x: number; y: number; time: number } | null>(null);
   127→
   128→  const isSandbox = scenarioState.mode === "sandbox";
   129→  const scenarioColors = SCENARIO_COLORS[scenarioState.mode];
   130→
   131→  // Compute conflicts once when tasks change
   132→  const { conflicts, conflictIndices } = useMemo(() => {
   133→    const detected = detectConflicts(tasks);
   134→    const indices = getConflictingTaskIndices(detected);
   135→    return { conflicts: detected, conflictIndices: indices };
   136→  }, [tasks]);
   137→
   138→  // Resize observer to track container size
   139→  useEffect(() => {
   140→    if (!containerRef.current) return;
   141→
   142→    const resizeObserver = new ResizeObserver((entries) => {
   143→      const entry = entries[0];
   144→      if (entry) {
   145→        const { width, height } = entry.contentRect;
   146→        const currentState = viewportStore.getState();
   147→        if (currentState.width !== width || currentState.height !== height) {
   148→          viewportStore.setSize(width, height);
   149→        }
   150→      }
   151→    });
   152→
   153→    resizeObserver.observe(containerRef.current);
   154→    return () => resizeObserver.disconnect();
   155→  }, []);
   156→
