   399→  const worldHeight = Math.abs(WORLD_BOUNDS.minY - WORLD_BOUNDS.maxY);
   400→  const scaleX = minimapWidth / worldWidth;
   401→  const scaleY = minimapHeight / worldHeight;
   402→
   403→  const visibleWidth = state.width / state.zoom;
   404→  const visibleHeight = state.height / state.zoom;
