import { useCallback, useEffect, useMemo, useRef } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import * as THREE from "three";
import {
  getLODLevel,
  getLODOpacity,
  useViewport,
  viewportStore,
  WORLD_BOUNDS,
} from "../../stores/viewport";
import { useInteraction } from "../../stores/interaction";
import { useScenario, SCENARIO_COLORS } from "../../stores/scenario";
import { MacroHeatmapCells, MacroYearMarkers } from "../../render/MacroLayer";
import { MesoTaskBlocks, MesoGridLines } from "../../render/MesoLayer";
import { MicroTaskCards, MicroTaskLabels, MicroWeeklyGrid, MicroRowBackgrounds } from "../../render/MicroLayer";
import { RenderIndicator } from "./RenderIndicator";
import type { TaskSoA } from "../../utils/mockData";
import { detectConflicts, getConflictingTaskIndices } from "../../utils/conflictDetection";

interface CanvasContainerProps {
  tasks: TaskSoA;
}

// Unified camera controller - syncs Three.js camera with viewport state
function UnifiedCameraController() {
  const { state } = useViewport();
  const { camera, size } = useThree();
  const loggedRef = useRef(false);

  useFrame(() => {
    if (camera instanceof THREE.OrthographicCamera) {
      // Update camera position
      camera.position.set(state.x, state.y, 100);

      // Update frustum based on viewport size and zoom
      const halfWidth = size.width / 2 / state.zoom;
      const halfHeight = size.height / 2 / state.zoom;
      camera.left = -halfWidth;
      camera.right = halfWidth;
      camera.top = halfHeight;
      camera.bottom = -halfHeight;
      camera.updateProjectionMatrix();

      // Debug log once
      if (!loggedRef.current) {
        loggedRef.current = true;
        console.log("[UnifiedCanvas Camera]", {
          position: [state.x, state.y, 100],
          frustum: { left: -halfWidth, right: halfWidth, top: halfHeight, bottom: -halfHeight },
          zoom: state.zoom,
        });
      }
    }
  });

  return null;
}

// LOD Layer wrapper - controls visibility via Three.js group
interface LODLayerProps {
  visible: boolean;
  opacity: number;
  children: React.ReactNode;
}

function LODLayer({ visible, opacity, children }: LODLayerProps) {
  const groupRef = useRef<THREE.Group>(null);

  useFrame(() => {
    if (groupRef.current) {
      groupRef.current.visible = visible && opacity > 0.01;
    }
  });

  if (!visible && opacity < 0.01) return null;

  return <group ref={groupRef}>{children}</group>;
}

// Props for unified scene
interface UnifiedSceneProps {
  tasks: TaskSoA;
  conflictIndices: Set<number>;
  onTaskClick: (index: number) => void;
}

// Unified scene containing all LOD layers
function UnifiedScene({ tasks, conflictIndices, onTaskClick }: UnifiedSceneProps) {
  const { state } = useViewport();
  const lodLevel = getLODLevel(state.zoom);
  const lodOpacity = getLODOpacity(state.zoom);

  return (
    <>
      <UnifiedCameraController />

      {/* MACRO Layer - Heatmap (visible when zoomed out) */}
      <LODLayer visible={lodLevel === "MACRO" || lodOpacity.macro > 0.01} opacity={lodOpacity.macro}>
        <MacroHeatmapCells tasks={tasks} />
        <MacroYearMarkers />
      </LODLayer>

      {/* MESO Layer - Task Blocks (default working view) */}
      <LODLayer visible={lodLevel === "MESO" || lodOpacity.meso > 0.01} opacity={lodOpacity.meso}>
        <MesoTaskBlocks tasks={tasks} conflictIndices={conflictIndices} onTaskClick={onTaskClick} />
        <MesoGridLines />
      </LODLayer>

      {/* MICRO Layer - Task Cards with labels (visible when zoomed in) */}
      <LODLayer visible={lodLevel === "MICRO" || lodOpacity.micro > 0.01} opacity={lodOpacity.micro}>
        <MicroRowBackgrounds />
        <MicroWeeklyGrid />
        <MicroTaskCards tasks={tasks} />
        <MicroTaskLabels tasks={tasks} />
      </LODLayer>
    </>
  );
}

export function CanvasContainer({ tasks }: CanvasContainerProps) {
  const { state, actions } = useViewport();
  const { state: interactionState, actions: interactionActions } = useInteraction();
  const { state: scenarioState } = useScenario();
  const containerRef = useRef<HTMLDivElement>(null);
  const dragStartRef = useRef<{ x: number; y: number; time: number } | null>(null);
  const lastPosRef = useRef<{ x: number; y: number; time: number } | null>(null);

  const isSandbox = scenarioState.mode === "sandbox";
  const scenarioColors = SCENARIO_COLORS[scenarioState.mode];

  // Compute conflicts once when tasks change
  const { conflicts, conflictIndices } = useMemo(() => {
    const detected = detectConflicts(tasks);
    const indices = getConflictingTaskIndices(detected);
    return { conflicts: detected, conflictIndices: indices };
  }, [tasks]);

  // Resize observer to track container size
  useEffect(() => {
    if (!containerRef.current) return;

    const resizeObserver = new ResizeObserver((entries) => {
      const entry = entries[0];
      if (entry) {
        const { width, height } = entry.contentRect;
        const currentState = viewportStore.getState();
        if (currentState.width !== width || currentState.height !== height) {
          viewportStore.setSize(width, height);
        }
      }
    });

    resizeObserver.observe(containerRef.current);
    return () => resizeObserver.disconnect();
  }, []);

  // Inertia animation loop
  useEffect(() => {
    let animationId: number;

    const animate = () => {
      viewportStore.applyInertia();
      animationId = requestAnimationFrame(animate);
    };

    animationId = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(animationId);
  }, []);

  // Mouse down handler
  const handleMouseDown = useCallback(
    (e: React.MouseEvent) => {
      if (e.button !== 0) return;
      e.preventDefault();
      actions.startDrag();
      const now = performance.now();
      dragStartRef.current = { x: e.clientX, y: e.clientY, time: now };
      lastPosRef.current = { x: e.clientX, y: e.clientY, time: now };
    },
    [actions]
  );

  // Mouse move handler
  const handleMouseMove = useCallback(
    (e: React.MouseEvent) => {
      if (!state.isDragging || !lastPosRef.current) return;

      const dx = e.clientX - lastPosRef.current.x;
      const dy = e.clientY - lastPosRef.current.y;
      actions.pan(dx, dy);

      const now = performance.now();
      lastPosRef.current = { x: e.clientX, y: e.clientY, time: now };
    },
    [state.isDragging, actions]
  );

  // Mouse up handler
  const handleMouseUp = useCallback(
    (e: React.MouseEvent) => {
      if (!state.isDragging || !lastPosRef.current || !dragStartRef.current) return;

      const dt = performance.now() - lastPosRef.current.time;
      const dx = e.clientX - lastPosRef.current.x;
      const dy = e.clientY - lastPosRef.current.y;

      const vx = dt > 0 ? (dx / dt) * 16 : 0;
      const vy = dt > 0 ? (dy / dt) * 16 : 0;

      actions.endDrag(vx, vy);
      dragStartRef.current = null;
      lastPosRef.current = null;
    },
    [state.isDragging, actions]
  );

  // Mouse leave handler
  const handleMouseLeave = useCallback(() => {
    if (state.isDragging) {
      actions.endDrag(0, 0);
      dragStartRef.current = null;
      lastPosRef.current = null;
    }
  }, [state.isDragging, actions]);

  // Wheel handler for zoom
  const handleWheel = useCallback(
    (e: React.WheelEvent) => {
      e.preventDefault();
      const rect = containerRef.current?.getBoundingClientRect();
      if (!rect) return;

      const screenX = e.clientX - rect.left;
      const screenY = e.clientY - rect.top;
      const factor = e.deltaY < 0 ? 1.1 : 1 / 1.1;

      actions.zoomToPoint(factor, screenX, screenY);
    },
    [actions]
  );

  // Calculate LOD info for display
  const lodLevel = getLODLevel(state.zoom);
  const lodOpacity = getLODOpacity(state.zoom);

  // Handle task click for selection
  const handleTaskClick = useCallback(
    (taskIndex: number) => {
      const taskId = tasks.ids[taskIndex]?.toString() ?? null;
      if (interactionState.selectedTaskIndex === taskIndex) {
        interactionActions.clearSelection();
      } else {
        interactionActions.selectTask(taskId, taskIndex);
      }
    },
    [tasks.ids, interactionState.selectedTaskIndex, interactionActions]
  );

  // Canvas dimensions
  const canvasWidth = state.width > 0 ? state.width : 800;
  const canvasHeight = state.height > 0 ? state.height : 600;

  return (
    <div
      ref={containerRef}
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseLeave}
      onWheel={handleWheel}
      style={{
        position: "absolute",
        inset: 0,
        backgroundColor: "var(--mms-bg-canvas)",
        cursor: state.isDragging ? "grabbing" : "grab",
        overflow: "hidden",
        userSelect: "none",
        boxShadow: isSandbox ? `inset 0 0 0 3px ${scenarioColors.accent}` : "none",
        transition: "box-shadow 200ms ease-in-out",
      }}
    >
      {/* Single unified Canvas containing all LOD layers */}
      <div
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          width: canvasWidth,
          height: canvasHeight,
        }}
      >
        <Canvas
          gl={{ antialias: true, alpha: false, preserveDrawingBuffer: true }}
          orthographic
          camera={{
            position: [730, -1536, 100],
            zoom: 1,
            near: 0.1,
            far: 1000,
          }}
        >
          <color attach="background" args={["#1a1a2e"]} />
          <UnifiedScene
            tasks={tasks}
            conflictIndices={conflictIndices}
            onTaskClick={handleTaskClick}
          />
        </Canvas>
      </div>

      {/* Canvas info overlay */}
      <div
        style={{
          position: "absolute",
          top: "50%",
          left: "50%",
          transform: "translate(-50%, -50%)",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          gap: "8px",
          pointerEvents: "none",
        }}
      >
        <div
          style={{
            fontSize: "24px",
            fontWeight: 600,
            color: "var(--mms-text-secondary)",
          }}
        >
          Semantic Zoom Canvas
        </div>
        <div style={{ color: "var(--mms-text-muted)", fontSize: "14px" }}>
          Zoom: {(state.zoom * 100).toFixed(0)}% ({state.zoom.toFixed(2)}x) |{" "}
          <span
            style={{
              color:
                lodLevel === "MACRO"
                  ? "#f0ab00"
                  : lodLevel === "MESO"
                    ? "#0066cc"
                    : "#3e8635",
              fontWeight: 600,
            }}
          >
            {lodLevel}
          </span>
        </div>
        <div style={{ color: "var(--mms-text-muted)", fontSize: "12px" }}>
          Camera: ({state.x.toFixed(0)}, {state.y.toFixed(0)})
        </div>
        <div style={{ color: "var(--mms-text-muted)", fontSize: "12px" }}>
          LOD Opacity: M={lodOpacity.macro.toFixed(2)} E={lodOpacity.meso.toFixed(2)} I=
          {lodOpacity.micro.toFixed(2)}
        </div>
        <div style={{ color: "var(--mms-text-muted)", fontSize: "11px", marginTop: "8px" }}>
          Drag to pan | Scroll to zoom | Click task to select
        </div>
        {isSandbox && (
          <div style={{ color: scenarioColors.accent, fontSize: "12px", marginTop: "4px", fontWeight: 600 }}>
            SANDBOX MODE - Changes won&apos;t affect baseline
          </div>
        )}
        {conflicts.length > 0 && (
          <div style={{ color: "#EF4444", fontSize: "12px", marginTop: "4px" }}>
            Conflicts: {conflicts.length} ({conflictIndices.size} tasks)
          </div>
        )}
        {interactionState.selectedTaskIndex !== null && (
          <div style={{ color: "#06B6D4", fontSize: "12px", marginTop: "4px" }}>
            Selected: Task #{interactionState.selectedTaskIndex}
            {conflictIndices.has(interactionState.selectedTaskIndex) && (
              <span style={{ color: "#EF4444" }}> (IN CONFLICT)</span>
            )}
          </div>
        )}
      </div>

      {/* Minimap */}
      <Minimap />

      {/* Hidden DOM element for E2E testing */}
      <RenderIndicator
        taskCount={tasks.count}
        conflictCount={conflicts.length}
      />
    </div>
  );
}

// Minimap component
function Minimap() {
  const { state, actions } = useViewport();
  const minimapWidth = 180;
  const minimapHeight = 120;

  const worldWidth = WORLD_BOUNDS.maxX - WORLD_BOUNDS.minX;
  const worldHeight = Math.abs(WORLD_BOUNDS.minY - WORLD_BOUNDS.maxY);
  const scaleX = minimapWidth / worldWidth;
  const scaleY = minimapHeight / worldHeight;

  const visibleWidth = state.width / state.zoom;
  const visibleHeight = state.height / state.zoom;
  const rectX = (state.x - visibleWidth / 2 - WORLD_BOUNDS.minX) * scaleX;
  const rectY = Math.abs(state.y + visibleHeight / 2 - WORLD_BOUNDS.maxY) * scaleY;
  const rectW = visibleWidth * scaleX;
  const rectH = visibleHeight * scaleY;

  const handleClick = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const clickX = e.clientX - rect.left;
    const clickY = e.clientY - rect.top;

    const worldX = WORLD_BOUNDS.minX + clickX / scaleX;
    const worldY = WORLD_BOUNDS.maxY - clickY / scaleY;

    const dx = (state.x - worldX) * state.zoom;
    const dy = (state.y - worldY) * state.zoom;
    actions.pan(-dx, -dy);
  };

  return (
    <div
      onClick={handleClick}
      style={{
        position: "absolute",
        bottom: "16px",
        right: "16px",
        width: `${minimapWidth}px`,
        height: `${minimapHeight}px`,
        backgroundColor: "var(--mms-bg-panel)",
        borderRadius: "4px",
        border: "1px solid var(--mms-text-muted)",
        overflow: "hidden",
        cursor: "pointer",
      }}
    >
      <div
        style={{
          position: "absolute",
          inset: 0,
          background: `
            linear-gradient(to right,
              rgba(100, 100, 200, 0.3) 0%,
              rgba(200, 150, 50, 0.3) 50%,
              rgba(100, 200, 100, 0.3) 100%
            )
          `,
        }}
      />
      <div
        style={{
          position: "absolute",
          left: `${Math.max(0, Math.min(minimapWidth - rectW, rectX))}px`,
          top: `${Math.max(0, Math.min(minimapHeight - rectH, rectY))}px`,
          width: `${Math.max(4, Math.min(minimapWidth, rectW))}px`,
          height: `${Math.max(4, Math.min(minimapHeight, rectH))}px`,
          border: "2px solid var(--mms-accent-baseline)",
          backgroundColor: "rgba(0, 102, 204, 0.2)",
          borderRadius: "2px",
          pointerEvents: "none",
        }}
      />
      <div
        style={{
          position: "absolute",
          bottom: "4px",
          left: "4px",
          fontSize: "10px",
          color: "var(--mms-text-muted)",
          textShadow: "0 0 4px var(--mms-bg-panel)",
        }}
      >
        12 years × 128 trains
      </div>
    </div>
  );
}

