     9→import {
    10→  TASK_HEIGHT,
    11→  TRAIN_HEIGHT,
    12→  DAY_WIDTH,
    13→  TRAIN_COUNT,
    14→  PLANNING_YEARS,
    15→} from "../utils/constants";
    16→
