    35→// Task blocks using InstancedMesh for performance
    36→function TaskBlocks({ tasks, conflictIndices, onTaskClick }: TaskBlocksProps) {
    37→  const meshRef = useRef<THREE.InstancedMesh>(null);
    38→  const { state: interactionState } = useInteraction();
    39→  const baseColorsRef = useRef<Float32Array | null>(null);
    40→
    41→  const typeColors: [number, number, number][] = useMemo(() => [
    42→    TASK_COLORS_RGB.preventive,
    43→    TASK_COLORS_RGB.corrective,
    44→    TASK_COLORS_RGB.inspection,
    45→    TASK_COLORS_RGB.overhaul,
    46→  ], []);
    47→
    48→  // Create instance matrices and colors
    49→  const { matrices, colors } = useMemo(() => {
    50→    const dummy = new THREE.Object3D();
    51→    const matrices = new Float32Array(tasks.count * 16);
    52→    const colors = new Float32Array(tasks.count * 3);
    53→
    54→    for (let i = 0; i < tasks.count; i++) {
    55→      // Calculate position
    56→      const x = tasks.startDays[i]! * DAY_WIDTH + (tasks.durations[i]! * DAY_WIDTH) / 2;
    57→      const y = -tasks.trainIds[i]! * TRAIN_HEIGHT - TRAIN_HEIGHT / 2;
    58→      // Conflicts render slightly in front
    59→      const z = conflictIndices?.has(i) ? 1 : 0;
    60→
    61→      // Calculate size
    62→      const width = Math.max(tasks.durations[i]! * DAY_WIDTH - 2, 4);
    63→      const height = TASK_HEIGHT;
    64→
    65→      // Set transform
    66→      dummy.position.set(x, y, z);
    67→      dummy.scale.set(width, height, 1);
    68→      dummy.updateMatrix();
    69→      dummy.matrix.toArray(matrices, i * 16);
    70→
    71→      // Set color based on task type (or conflict)
    72→      let color: [number, number, number];
    73→      if (conflictIndices?.has(i)) {
    74→        color = CONFLICT_COLOR;
    75→      } else {
    76→        const typeIndex = tasks.types[i]!;
    77→        color = typeColors[typeIndex] ?? typeColors[0]!;
    78→      }
    79→      colors[i * 3] = color[0];
    80→      colors[i * 3 + 1] = color[1];
    81→      colors[i * 3 + 2] = color[2];
    82→    }
    83→
    84→    // Store base colors for hover/selection effects
    85→    baseColorsRef.current = colors.slice();
    86→
    87→    return { matrices, colors };
    88→  }, [tasks, typeColors, conflictIndices]);
    89→
    90→  // Apply matrices AND colors to mesh after it's mounted
    91→  useEffect(() => {
    92→    if (!meshRef.current) return;
    93→
    94→    const mesh = meshRef.current;
    95→
    96→    // Apply matrices
    97→    const matrix = new THREE.Matrix4();
    98→    for (let i = 0; i < tasks.count; i++) {
    99→      matrix.fromArray(matrices, i * 16);
   100→      mesh.setMatrixAt(i, matrix);
   101→    }
   102→    mesh.instanceMatrix.needsUpdate = true;
   103→
   104→    // Apply colors - create instanceColor attribute if it doesn't exist
   105→    if (!mesh.instanceColor) {
   106→      mesh.instanceColor = new THREE.InstancedBufferAttribute(colors, 3);
   107→    } else {
   108→      // Update existing color buffer
   109→      const colorAttr = mesh.instanceColor as THREE.InstancedBufferAttribute;
   110→      for (let i = 0; i < tasks.count; i++) {
   111→        colorAttr.setXYZ(i, colors[i * 3]!, colors[i * 3 + 1]!, colors[i * 3 + 2]!);
   112→      }
   113→    }
   114→    mesh.instanceColor.needsUpdate = true;
   115→
   116→    // DEBUG: Log first few task positions and colors
   117→    console.log('[TaskBlocks] Applied', tasks.count, 'instances with colors');
   118→  }, [matrices, colors, tasks.count]);
   119→
   120→  // Update colors based on selection/hover state
   121→  useEffect(() => {
   122→    if (!meshRef.current || !meshRef.current.instanceColor || !baseColorsRef.current) return;
   123→
   124→    const colorAttr = meshRef.current.instanceColor as THREE.InstancedBufferAttribute;
   125→    const baseColors = baseColorsRef.current;
   126→
   127→    for (let i = 0; i < tasks.count; i++) {
   128→      let r = baseColors[i * 3]!;
   129→      let g = baseColors[i * 3 + 1]!;
   130→      let b = baseColors[i * 3 + 2]!;
