import { useRef, useEffect, useMemo, useCallback } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import type { ThreeEvent } from "@react-three/fiber";
import * as THREE from "three";
import { useViewport, WORLD_BOUNDS } from "../stores/viewport";
import { useInteraction } from "../stores/interaction";
import type { TaskSoA } from "../utils/mockData";
import { TASK_COLORS_RGB } from "../types/task";
import {
  TASK_HEIGHT,
  TRAIN_HEIGHT,
  DAY_WIDTH,
  TRAIN_COUNT,
  PLANNING_YEARS,
} from "../utils/constants";

interface MesoLayerProps {
  tasks: TaskSoA;
  width?: number;
  height?: number;
  opacity?: number;
}

// Selection highlight color (cyan)
const SELECTION_COLOR: [number, number, number] = [0.02, 0.71, 0.83]; // #06B6D4
// Conflict highlight color (red)
const CONFLICT_COLOR: [number, number, number] = [0.94, 0.27, 0.27]; // #EF4444

interface TaskBlocksProps {
  tasks: TaskSoA;
  conflictIndices?: Set<number>;
  onTaskClick?: (index: number) => void;
}

// Task blocks using InstancedMesh for performance
function TaskBlocks({ tasks, conflictIndices, onTaskClick }: TaskBlocksProps) {
  const meshRef = useRef<THREE.InstancedMesh>(null);
  const { state: interactionState } = useInteraction();
  const baseColorsRef = useRef<Float32Array | null>(null);

  const typeColors: [number, number, number][] = useMemo(() => [
    TASK_COLORS_RGB.preventive,
    TASK_COLORS_RGB.corrective,
    TASK_COLORS_RGB.inspection,
    TASK_COLORS_RGB.overhaul,
  ], []);

  // Create instance matrices and colors
  const { matrices, colors } = useMemo(() => {
    const dummy = new THREE.Object3D();
    const matrices = new Float32Array(tasks.count * 16);
    const colors = new Float32Array(tasks.count * 3);

    for (let i = 0; i < tasks.count; i++) {
      // Calculate position
      const x = tasks.startDays[i]! * DAY_WIDTH + (tasks.durations[i]! * DAY_WIDTH) / 2;
      const y = -tasks.trainIds[i]! * TRAIN_HEIGHT - TRAIN_HEIGHT / 2;
      // Conflicts render slightly in front
      const z = conflictIndices?.has(i) ? 1 : 0;

      // Calculate size
      const width = Math.max(tasks.durations[i]! * DAY_WIDTH - 2, 4);
      const height = TASK_HEIGHT;

      // Set transform
      dummy.position.set(x, y, z);
      dummy.scale.set(width, height, 1);
      dummy.updateMatrix();
      dummy.matrix.toArray(matrices, i * 16);

      // Set color based on task type (or conflict)
      let color: [number, number, number];
      if (conflictIndices?.has(i)) {
        color = CONFLICT_COLOR;
      } else {
        const typeIndex = tasks.types[i]!;
        color = typeColors[typeIndex] ?? typeColors[0]!;
      }
      colors[i * 3] = color[0];
      colors[i * 3 + 1] = color[1];
      colors[i * 3 + 2] = color[2];
    }

    // Store base colors for hover/selection effects
    baseColorsRef.current = colors.slice();

    return { matrices, colors };
  }, [tasks, typeColors, conflictIndices]);

  // Apply matrices AND colors to mesh after it's mounted
  useEffect(() => {
    if (!meshRef.current) return;

    const mesh = meshRef.current;

    // Apply matrices
    const matrix = new THREE.Matrix4();
    for (let i = 0; i < tasks.count; i++) {
      matrix.fromArray(matrices, i * 16);
      mesh.setMatrixAt(i, matrix);
    }
    mesh.instanceMatrix.needsUpdate = true;

    // Apply colors - create instanceColor attribute if it doesn't exist
    if (!mesh.instanceColor) {
      mesh.instanceColor = new THREE.InstancedBufferAttribute(colors, 3);
    } else {
      // Update existing color buffer
      const colorAttr = mesh.instanceColor as THREE.InstancedBufferAttribute;
      for (let i = 0; i < tasks.count; i++) {
        colorAttr.setXYZ(i, colors[i * 3]!, colors[i * 3 + 1]!, colors[i * 3 + 2]!);
      }
    }
    mesh.instanceColor.needsUpdate = true;

    // DEBUG: Log first few task positions and colors
    console.log('[TaskBlocks] Applied', tasks.count, 'instances with colors');
  }, [matrices, colors, tasks.count]);

  // Update colors based on selection/hover state
  useEffect(() => {
    if (!meshRef.current || !meshRef.current.instanceColor || !baseColorsRef.current) return;

    const colorAttr = meshRef.current.instanceColor as THREE.InstancedBufferAttribute;
    const baseColors = baseColorsRef.current;

    for (let i = 0; i < tasks.count; i++) {
      let r = baseColors[i * 3]!;
      let g = baseColors[i * 3 + 1]!;
      let b = baseColors[i * 3 + 2]!;

      // Selection effect - use selection color
      if (interactionState.selectedTaskIndex === i) {
        r = SELECTION_COLOR[0];
        g = SELECTION_COLOR[1];
        b = SELECTION_COLOR[2];
      }
      // Hover effect - brighten by 20%
      else if (interactionState.hoveredTaskIndex === i) {
        r = Math.min(1, r * 1.2);
        g = Math.min(1, g * 1.2);
        b = Math.min(1, b * 1.2);
      }

      colorAttr.setXYZ(i, r, g, b);
    }

    colorAttr.needsUpdate = true;
  }, [interactionState.selectedTaskIndex, interactionState.hoveredTaskIndex, tasks.count]);

