import type { Task, TaskType } from "../types/task";

// Seeded random number generator for deterministic data
function seededRandom(seed: number) {
  return function () {
    seed = (seed * 1103515245 + 12345) & 0x7fffffff;
    return seed / 0x7fffffff;
  };
}

// Generate mock task data
export function generateMockTasks(
  trainCount: number = 128,
  yearsSpan: number = 12,
  tasksPerTrainPerYear: number = 4
): Task[] {
  const random = seededRandom(42); // Deterministic seed
  const tasks: Task[] = [];
  const daysPerYear = 365;

  const taskTypes: TaskType[] = ["preventive", "corrective", "inspection", "overhaul"];
  const taskNames: Record<TaskType, string[]> = {
    preventive: ["PM-A", "PM-B", "PM-C", "PM-D"],
    corrective: ["CM-Brake", "CM-Door", "CM-HVAC", "CM-Traction"],
    inspection: ["INS-Safety", "INS-Wheel", "INS-Pantograph", "INS-Bogie"],
    overhaul: ["OH-Major", "OH-Minor", "OH-Mid-life", "OH-Component"],
  };

  let taskId = 0;

  for (let trainId = 0; trainId < trainCount; trainId++) {
    for (let year = 0; year < yearsSpan; year++) {
      const numTasks = Math.floor(tasksPerTrainPerYear * (0.7 + random() * 0.6));

      for (let t = 0; t < numTasks; t++) {
        const type = taskTypes[Math.floor(random() * taskTypes.length)] as TaskType;
        const names = taskNames[type];
        const name = names[Math.floor(random() * names.length)] as string;

        // Random day within the year
        const dayInYear = Math.floor(random() * daysPerYear);
        const startDay = year * daysPerYear + dayInYear;

        // Duration based on task type
        let duration: number;
        switch (type) {
          case "preventive":
            duration = Math.floor(1 + random() * 2); // 1-3 days
            break;
          case "corrective":
            duration = Math.floor(1 + random() * 3); // 1-4 days
            break;
          case "inspection":
            duration = Math.floor(1 + random() * 1); // 1-2 days
            break;
          case "overhaul":
            duration = Math.floor(5 + random() * 10); // 5-15 days
            break;
        }

        tasks.push({
          id: `TASK-${String(taskId++).padStart(6, "0")}`,
          trainId,
          type,
          startDay,
          duration,
          name,
          status: random() < 0.1 ? "conflict" : "scheduled",
        });
      }
    }
  }

  return tasks;
}

// Generate task data optimized for rendering (Structure of Arrays)
export interface TaskSoA {
  count: number;
  ids: string[];
  trainIds: Int32Array;
  types: Uint8Array; // 0=preventive, 1=corrective, 2=inspection, 3=overhaul
  startDays: Float32Array;
  durations: Float32Array;
  statuses: Uint8Array; // 0=scheduled, 1=in_progress, 2=completed, 3=conflict
}

export function tasksToSoA(tasks: Task[]): TaskSoA {
  const count = tasks.length;
  const ids: string[] = [];
  const trainIds = new Int32Array(count);
  const types = new Uint8Array(count);
  const startDays = new Float32Array(count);
  const durations = new Float32Array(count);
  const statuses = new Uint8Array(count);

  const typeMap: Record<TaskType, number> = {
    preventive: 0,
    corrective: 1,
    inspection: 2,
    overhaul: 3,
  };

  const statusMap: Record<string, number> = {
    scheduled: 0,
    in_progress: 1,
    completed: 2,
    conflict: 3,
  };

  for (let i = 0; i < count; i++) {
    const task = tasks[i]!;
    ids.push(task.id);
    trainIds[i] = task.trainId;
    types[i] = typeMap[task.type];
    startDays[i] = task.startDay;
    durations[i] = task.duration;
    statuses[i] = statusMap[task.status] ?? 0;
  }

  return { count, ids, trainIds, types, startDays, durations, statuses };
}

