import { useMemo, useRef, useEffect } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import * as THREE from "three";
import { useViewport, WORLD_BOUNDS } from "../stores/viewport";
import type { TaskSoA } from "../utils/mockData";
import {
  DAYS_PER_CELL,
  DAY_WIDTH,
  CELL_WIDTH,
  CELL_HEIGHT,
  TRAIN_COUNT,
  PLANNING_YEARS,
} from "../utils/constants";

// Viridis color scale (d3-scale-chromatic)
const VIRIDIS_COLORS: [number, number, number][] = [
  [0.267004, 0.004874, 0.329415], // 0.0 - dark purple
  [0.282327, 0.140926, 0.457517], // 0.1
  [0.253935, 0.265254, 0.529983], // 0.2
  [0.206756, 0.371758, 0.553117], // 0.3
  [0.163625, 0.471133, 0.558148], // 0.4
  [0.127568, 0.566949, 0.550556], // 0.5
  [0.134692, 0.658636, 0.517649], // 0.6
  [0.266941, 0.748751, 0.440573], // 0.7
  [0.477504, 0.821444, 0.318195], // 0.8
  [0.741388, 0.873449, 0.149561], // 0.9
  [0.993248, 0.906157, 0.143936], // 1.0 - bright yellow
];

function interpolateViridis(t: number): [number, number, number] {
  const clampedT = Math.max(0, Math.min(1, t));
  const idx = clampedT * (VIRIDIS_COLORS.length - 1);
  const lowerIdx = Math.floor(idx);
  const upperIdx = Math.min(lowerIdx + 1, VIRIDIS_COLORS.length - 1);
  const frac = idx - lowerIdx;

  const lower = VIRIDIS_COLORS[lowerIdx]!;
  const upper = VIRIDIS_COLORS[upperIdx]!;

  return [
    lower[0] + (upper[0] - lower[0]) * frac,
    lower[1] + (upper[1] - lower[1]) * frac,
    lower[2] + (upper[2] - lower[2]) * frac,
  ];
}

interface HeatmapData {
  matrices: Float32Array;
  colors: Float32Array;
  cellCount: number;
}

function computeHeatmap(tasks: TaskSoA, totalMonths: number, trainCount: number): HeatmapData {
  // Aggregate task counts per cell
  const cellCounts = new Uint16Array(trainCount * totalMonths);
  let maxCount = 0;

  for (let i = 0; i < tasks.count; i++) {
    const trainId = tasks.trainIds[i]!;
    const startDay = tasks.startDays[i]!;
    const duration = tasks.durations[i]!;

    // Find which month cells this task spans
    const startMonth = Math.floor(startDay / DAYS_PER_CELL);
    const endMonth = Math.floor((startDay + duration) / DAYS_PER_CELL);

    for (let month = startMonth; month <= endMonth && month < totalMonths; month++) {
      if (trainId < trainCount && month >= 0) {
        const cellIdx = trainId * totalMonths + month;
        const newCount = (cellCounts[cellIdx] ?? 0) + 1;
        cellCounts[cellIdx] = newCount;
        if (newCount > maxCount) {
          maxCount = newCount;
        }
      }
    }
  }

  // Generate matrices and colors for each cell
  const cellCount = trainCount * totalMonths;
  const matrices = new Float32Array(cellCount * 16);
  const colors = new Float32Array(cellCount * 3);
  const dummy = new THREE.Object3D();

  for (let trainIdx = 0; trainIdx < trainCount; trainIdx++) {
    for (let month = 0; month < totalMonths; month++) {
      const cellIdx = trainIdx * totalMonths + month;
      const count = cellCounts[cellIdx]!;

      // Position: center of cell
      const x = month * CELL_WIDTH + CELL_WIDTH / 2;
      const y = -trainIdx * CELL_HEIGHT - CELL_HEIGHT / 2;

      dummy.position.set(x, y, -0.1); // Slightly behind task blocks
      dummy.scale.set(CELL_WIDTH - 1, CELL_HEIGHT - 1, 1); // 1px gap
      dummy.updateMatrix();
      dummy.matrix.toArray(matrices, cellIdx * 16);

      // Color: viridis interpolation
      const normalized = maxCount > 0 ? count / maxCount : 0;

