  --mms-accent-baseline: #0066cc;
  --mms-accent-scenario: #6753ac;

  /* Selection colors */
  --mms-selection: #06b6d4;
}

/* Dark Theme */
[data-theme="dark"] {
  /* Background colors */
  --mms-bg-primary: #151515;
  --mms-bg-canvas: #0a0a0a;
  --mms-bg-panel: #1f1f1f;
  --mms-bg-elevated: #292929;

  /* Text colors */
  --mms-text-primary: #ffffff;
  --mms-text-secondary: #c7c7c7;
  --mms-text-muted: #8a8a8a;
}

